  1→//! Multi-agent extraction from OpenClaw installations.
  2→//!
  3→//! Reads the `agents.list` array from `openclaw.json` and resolves each
  4→//! agent's workspace, identity metadata (theme), and a
  5→//! sanitized Moltis agent ID.
  6→
  7→use std::{
  8→    collections::HashSet,
  9→    path::{Path, PathBuf},
 10→};
 11→
 12→use {
 13→    serde::{Deserialize, Serialize},
 14→    tracing::{debug, info},
 15→};
 16→
 17→use crate::{detect::OpenClawDetection, identity, types::OpenClawConfig};
 18→
 19→/// Per-agent data extracted from OpenClaw, to be consumed by the gateway.
 20→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 21→pub struct ImportedAgent {
 22→    pub openclaw_id: String,
 23→    /// Sanitized Moltis-side agent ID; `"main"` for the default agent.
 24→    pub moltis_id: String,
 25→    pub is_default: bool,
 26→    pub name: Option<String>,
 27→    /// Agent theme (composed from creature/vibe, or explicit theme).
 28→    pub theme: Option<String>,
 29→    /// Resolved source workspace directory for this agent.
 30→    pub source_workspace: Option<PathBuf>,
 31→}
 32→
 33→/// Collection of all agents extracted from an OpenClaw installation.
 34→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 35→pub struct ImportedAgents {
 36→    pub agents: Vec<ImportedAgent>,
 37→}
 38→
 39→/// Sanitize an OpenClaw agent ID into a valid Moltis agent ID.
 40→///
 41→/// - Lowercase, replace non-alphanumeric with `-`, collapse `--`, trim `-`
 42→/// - Truncate to 50 characters
 43→/// - Append `-2`, `-3` etc. if the ID collides with an existing one or `"main"`
 44→pub fn sanitize_agent_id(raw: &str, existing_ids: &HashSet<String>) -> String {
 45→    let lowered: String = raw
 46→        .chars()
 47→        .map(|c| {
 48→            if c.is_ascii_alphanumeric() {
 49→                c.to_ascii_lowercase()
 50→            } else {
 51→                '-'
 52→            }
 53→        })
 54→        .collect();
 55→
 56→    // Collapse repeated dashes, trim leading/trailing dashes
 57→    let mut collapsed = String::with_capacity(lowered.len());
 58→    let mut prev_dash = true; // treat start as dash to trim leading
 59→    for c in lowered.chars() {
 60→        if c == '-' {
 61→            if !prev_dash {
 62→                collapsed.push('-');
 63→            }
 64→            prev_dash = true;
 65→        } else {
 66→            collapsed.push(c);
 67→            prev_dash = false;
 68→        }
 69→    }
 70→    let trimmed = collapsed.trim_end_matches('-');
 71→    let truncated = if trimmed.len() > 50 {
 72→        &trimmed[..50]
 73→    } else {
 74→        trimmed
 75→    };
 76→    let base = if truncated.is_empty() {
 77→        "agent".to_string()
 78→    } else {
 79→        truncated.to_string()
 80→    };
 81→
 82→    // Avoid collision with "main" or existing IDs
 83→    if base != "main" && !existing_ids.contains(&base) {
 84→        return base;
 85→    }
 86→
 87→    for suffix in 2..=999 {
 88→        let candidate = format!("{base}-{suffix}");
 89→        if !existing_ids.contains(&candidate) {
 90→            return candidate;
 91→        }
 92→    }
 93→
 94→    // Extremely unlikely fallback
 95→    format!("{base}-overflow")
 96→}
 97→
 98→/// Extract agent metadata from an OpenClaw installation.
 99→///
100→/// Reads `openclaw.json` and resolves each agent's workspace, identity,
101→/// theme. The default agent gets `moltis_id = "main"`.
102→pub fn import_agents(detection: &OpenClawDetection) -> ImportedAgents {
103→    let config = identity::load_config(&detection.home_dir);
104→    let mut agents = Vec::new();
105→    let mut used_ids: HashSet<String> = HashSet::new();
106→    used_ids.insert("main".to_string());
107→
108→    if !config.agents.list.is_empty() {
109→        agents = extract_from_config_list(&config, detection, &mut used_ids);
110→    }
111→
112→    // If config has no agent list but detection found agent dirs, synthesize entries
113→    if agents.is_empty() && !detection.agent_ids.is_empty() {
114→        agents = synthesize_from_detection(detection, &mut used_ids);
115→    }
116→
117→    let count = agents.len();
118→    let default_count = agents.iter().filter(|a| a.is_default).count();
119→    info!(
120→        agent_count = count,
121→        default_count, "openclaw agents: extraction complete"
122→    );
123→
124→    ImportedAgents { agents }
125→}
126→
127→/// Build `ImportedAgent` entries from the `agents.list` array in config.
128→fn extract_from_config_list(
129→    config: &OpenClawConfig,
130→    detection: &OpenClawDetection,
131→    used_ids: &mut HashSet<String>,
132→) -> Vec<ImportedAgent> {
133→    let mut agents = Vec::new();
134→
135→    for entry in &config.agents.list {
136→        let is_default = entry.default
137→            || (config.agents.list.len() == 1)
138→            || (agents.is_empty() && entry.id == "main");
139→
140→        let moltis_id = if is_default {
141→            "main".to_string()
142→        } else {
143→            let id = sanitize_agent_id(&entry.id, used_ids);
144→            used_ids.insert(id.clone());
145→            id
146→        };
147→
148→        let source_workspace =
149→            resolve_agent_workspace(entry.workspace.as_deref(), &entry.id, detection);
150→
151→        let theme = extract_agent_identity(&source_workspace, config);
152→
153→        debug!(
154→            openclaw_id = %entry.id,
155→            moltis_id = %moltis_id,
156→            is_default,
157→            name = ?entry.name,
158→            theme = ?theme,
159→            workspace = ?source_workspace,
160→            "openclaw agents: extracted agent"
161→        );
162→
163→        agents.push(ImportedAgent {
164→            openclaw_id: entry.id.clone(),
165→            moltis_id,
166→            is_default,
167→            name: entry.name.clone(),
168→            theme,
169→            source_workspace,
170→        });
171→    }
172→
173→    agents
174→}
175→
176→/// Synthesize minimal `ImportedAgent` entries from detected agent directories
177→/// when no config list is available.
178→fn synthesize_from_detection(
179→    detection: &OpenClawDetection,
180→    used_ids: &mut HashSet<String>,
181→) -> Vec<ImportedAgent> {
182→    let mut agents = Vec::new();
183→
184→    for (i, oc_id) in detection.agent_ids.iter().enumerate() {
185→        let is_default =
186→            oc_id == "main" || (i == 0 && !detection.agent_ids.contains(&"main".to_string()));
187→
188→        let moltis_id = if is_default {
189→            "main".to_string()
190→        } else {
191→            let id = sanitize_agent_id(oc_id, used_ids);
192→            used_ids.insert(id.clone());
193→            id
194→        };
195→
196→        let agent_dir = detection.home_dir.join("agents").join(oc_id);
197→        let source_workspace = resolve_agent_dir_workspace(&agent_dir)
198→            .or_else(|| Some(detection.workspace_dir.clone()));
199→
200→        debug!(
201→            openclaw_id = %oc_id,
202→            moltis_id = %moltis_id,
203→            is_default,
204→            "openclaw agents: synthesized agent from filesystem"
205→        );
206→
207→        agents.push(ImportedAgent {
208→            openclaw_id: oc_id.clone(),
209→            moltis_id,
210→            is_default,
211→            name: None,
212→            theme: None,
213→            source_workspace,
214→        });
215→    }
216→
217→    agents
218→}
219→
220→/// Resolve the workspace directory for a specific agent.
221→///
222→/// Priority: configured workspace path → remap basename under `~/` →
223→/// agent's `agent/` subdir → detection workspace
224→fn resolve_agent_workspace(
225→    configured_workspace: Option<&str>,
226→    agent_id: &str,
227→    detection: &OpenClawDetection,
228→) -> Option<PathBuf> {
229→    // 1. Configured workspace path (exact)
230→    if let Some(ws) = configured_workspace {
231→        let path = if PathBuf::from(ws).is_absolute() {
232→            PathBuf::from(ws)
233→        } else {
234→            detection.home_dir.join(ws)
235→        };
236→        if path.is_dir() {
237→            return Some(path);
238→        }
239→
240→        // 1b. Remap: basename under ~/ (cross-machine, e.g. /root/clawd → ~/clawd)
241→        let abs_path = PathBuf::from(ws);
242→        if let Some(basename) = abs_path.file_name()
243→            && let Some(user_home) = dirs_next::home_dir()
244→        {
245→            let remapped = user_home.join(basename);
246→            if remapped.is_dir() {
247→                debug!(
248→                    configured = ws,
249→                    remapped = %remapped.display(),
250→                    agent_id,
251→                    "openclaw agents: workspace remapped from config basename"
252→                );
253→                return Some(remapped);
254→            }
255→        }
256→    }
257→
258→    // 2. Agent's agent/ subdir (may contain IDENTITY.md, etc.)
259→    let agent_dir = detection.home_dir.join("agents").join(agent_id);
260→    if let Some(ws) = resolve_agent_dir_workspace(&agent_dir) {
261→        return Some(ws);
262→    }
263→
264→    // 3. Global workspace
265→    if detection.workspace_dir.is_dir() {
266→        return Some(detection.workspace_dir.clone());
267→    }
268→
269→    None
270→}
271→
272→/// Check for a workspace within an agent's directory structure.
273→fn resolve_agent_dir_workspace(agent_dir: &Path) -> Option<PathBuf> {
274→    let nested = agent_dir.join("agent");
275→    if nested.is_dir() {
276→        return Some(nested);
277→    }
278→    if agent_dir.is_dir() {
279→        return Some(agent_dir.to_path_buf());
280→    }
281→    None
282→}
283→
284→/// Extract theme from an agent's workspace IDENTITY.md or config.
285→fn extract_agent_identity(workspace: &Option<PathBuf>, config: &OpenClawConfig) -> Option<String> {
286→    // Try IDENTITY.md in the workspace
287→    if let Some(ws) = workspace {
288→        let identity_path = ws.join("IDENTITY.md");
289→        if let Ok(content) = std::fs::read_to_string(&identity_path) {
290→            let parsed = identity::parse_workspace_identity(&content);
291→            let theme = parsed
292→                .theme
293→                .or_else(|| identity::compose_theme(parsed.creature, parsed.vibe));
294→            if theme.is_some() {
295→                return theme;
296→            }
297→        }
298→    }
299→
300→    // Fall back to ui.assistant from config
301→    if let Some(assistant) = config.ui.assistant.as_ref() {
302→        let theme = assistant.theme.clone().or_else(|| {
303→            identity::compose_theme(assistant.creature.clone(), assistant.vibe.clone())
304→        });
305→        return theme;
306→    }
307→
308→    None
309→}
