207→/// A single auth profile credential entry.
208→#[derive(Debug, Clone, Deserialize)]
209→#[serde(tag = "type", rename_all = "snake_case")]
210→pub enum OpenClawAuthProfile {
211→    ApiKey {
212→        provider: String,
213→        key: Option<String>,
214→        email: Option<String>,
215→    },
216→    Token {
217→        provider: String,
218→        token: Option<String>,
219→        expires: Option<u64>,
220→        email: Option<String>,
221→    },
222→    Oauth {
223→        provider: String,
224→        #[serde(rename = "clientId")]
225→        client_id: Option<String>,
226→        email: Option<String>,
227→        #[serde(rename = "accessToken", alias = "access")]
228→        access_token: Option<String>,
229→        #[serde(rename = "refreshToken", alias = "refresh")]
230→        refresh_token: Option<String>,
231→        expires: Option<u64>,
232→        #[serde(rename = "accountId")]
233→        account_id: Option<String>,
234→    },
235→}
