237→impl OpenClawAuthProfile {
238→    /// The provider name for this profile.
239→    pub fn provider(&self) -> &str {
240→        match self {
241→            Self::ApiKey { provider, .. }
242→            | Self::Token { provider, .. }
243→            | Self::Oauth { provider, .. } => provider,
244→        }
245→    }
246→
247→    /// Extract the API key (only for `api_key` profiles).
248→    pub fn api_key(&self) -> Option<&str> {
249→        match self {
250→            Self::ApiKey { key, .. } => key.as_deref(),
251→            _ => None,
252→        }
253→    }
