292→/// A timestamp in OpenClaw records.
293→///
294→/// OpenClaw emits mixed formats:
295→/// - integer unix milliseconds (`1769582795764`)
296→/// - floating-point seconds or milliseconds
297→/// - ISO-8601 strings (`2026-01-28T06:46:35.758Z`)
298→#[derive(Debug, Clone, Deserialize)]
299→#[serde(untagged)]
300→pub enum OpenClawTimestamp {
301→    Integer(i64),
302→    Float(f64),
303→    Iso(String),
304→}
305→
306→impl OpenClawTimestamp {
307→    /// Convert to unix milliseconds.
308→    #[must_use]
309→    pub fn to_millis(&self) -> Option<u64> {
310→        match self {
311→            Self::Integer(v) => normalize_epoch(*v as f64),
312→            Self::Float(v) => normalize_epoch(*v),
313→            Self::Iso(s) => parse_iso_to_millis(s),
314→        }
315→    }
316→}
317→
318→fn normalize_epoch(value: f64) -> Option<u64> {
319→    if !value.is_finite() || value < 0.0 {
320→        return None;
321→    }
322→    // Treat very large values as milliseconds, otherwise seconds.
323→    let ms = if value >= 1_000_000_000_000.0 {
324→        value
325→    } else {
326→        value * 1000.0
327→    };
328→    Some(ms as u64)
329→}
330→
331→fn parse_iso_to_millis(s: &str) -> Option<u64> {
332→    use time::format_description::well_known::Rfc3339;
333→    let dt = time::OffsetDateTime::parse(s, &Rfc3339).ok()?;
334→    let nanos = dt.unix_timestamp_nanos();
335→    if nanos < 0 {
336→        return None;
337→    }
338→    Some((nanos / 1_000_000) as u64)
339→}
340→
341→/// OpenClaw message roles.
342→#[derive(Debug, Clone, Copy, PartialEq, Eq, Deserialize)]
343→#[serde(rename_all = "camelCase")]
344→pub enum OpenClawRole {
345→    User,
346→    Assistant,
347→    Tool,
348→    ToolResult,
349→    System,
350→}
351→
352→/// Message content — either a string or an array of content blocks.
353→#[derive(Debug, Clone, Deserialize)]
354→#[serde(untagged)]
355→pub enum OpenClawContent {
356→    Text(String),
357→    Blocks(Vec<serde_json::Value>),
358→}
359→
360→impl OpenClawContent {
361→    /// Extract as plain text, joining blocks if necessary.
362→    pub fn as_text(&self) -> String {
363→        match self {
364→            Self::Text(s) => s.clone(),
365→            Self::Blocks(blocks) => blocks
366→                .iter()
367→                .filter_map(|b| {
368→                    b.get("text")
369→                        .and_then(|t| t.as_str())
370→                        .map(|s| s.to_string())
371→                })
372→                .collect::<Vec<_>>()
373→                .join("\n"),
374→        }
375→    }
376→}
377→
378→// ── Session index (sessions.json) ────────────────────────────────────────────
379→
380→/// A single entry in the `sessions.json` index file.
381→///
382→/// The index maps logical session keys (e.g. `agent:main:main`) to metadata
383→/// including timestamps and origin information.
384→#[derive(Debug, Deserialize)]
385→pub struct OpenClawSessionIndexEntry {
386→    #[serde(rename = "sessionId")]
387→    pub session_id: Option<String>,
388→    #[serde(rename = "updatedAt")]
389→    pub updated_at: Option<u64>,
390→    pub origin: Option<OpenClawSessionOrigin>,
391→}
392→
393→/// Origin metadata for a session in `sessions.json`.
394→#[derive(Debug, Deserialize)]
395→pub struct OpenClawSessionOrigin {
396→    pub label: Option<String>,
397→    pub provider: Option<String>,
398→    #[serde(rename = "chatType")]
399→    pub chat_type: Option<String>,
400→}
401→
402→// ── MCP servers (OpenClaw format) ────────────────────────────────────────────
403→
404→/// A single MCP server entry in OpenClaw's config.
405→///
406→/// OpenClaw typically configures MCP servers in `mcp-servers.json` or within
407→/// `openclaw.json` plugins — the format matches the Claude Code MCP standard.
408→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
409→#[serde(default)]
410→pub struct OpenClawMcpServer {
411→    pub command: String,
412→    #[serde(default)]
413→    pub args: Vec<String>,
414→    #[serde(default)]
415→    pub env: HashMap<String, String>,
416→    #[serde(default = "default_true")]
417→    pub enabled: bool,
418→}
419→
420→fn default_true() -> bool {
421→    true
422→}
