    }

    #[test]
    fn parse_session_index_entry() {
        let json = r#"{
            "agent:main:main": {
                "sessionId": "d8da3601-1234-4abc-9def-aabbccddeeff",
                "updatedAt": 1770000000000,
                "origin": {
                    "label": "Fabien (@fabienpenso) id:377114917",
                    "provider": "telegram",
                    "chatType": "direct"
                }
            }
