            agent_ids: Vec::new(),
            session_count: 0,
            unsupported_channels: Vec::new(),
            has_workspace_files: false,
            workspace_files_found: Vec::new(),
        };

        let result = import_agents(&detection);
        assert!(result.agents.is_empty());
    }
}

