fn sanitize_special_chars() {
    let ids = HashSet::new();
    // Non-alphanumeric chars become `-`, then repeated dashes are collapsed
    assert_eq!(sanitize_agent_id("my_agent!@#test", &ids), "my-agent-test");
}

