        let result = import_agents(&detection);
        assert_eq!(result.agents.len(), 2);
        assert!(result.agents[0].model.is_none()); // main has no model override
        assert_eq!(
            result.agents[1].model.as_deref(),
            Some("anthropic/claude-haiku-3-5-20241022")
        );
    }

